window.COURSE_LANG = window.COURSE_LANG || {};
window.COURSE_LANG["cdl-doubles-triples"] = window.COURSE_LANG["cdl-doubles-triples"] || {};
window.COURSE_LANG["cdl-doubles-triples"]["es"] = [
  {"id":1,"q":"Al jalar dobles o triples, el remolque más cargado debe colocarse:","opts":["Primero, justo detrás del tractor","Segundo en la fila","Último en la fila","No importa dónde"],"re":"Coloca el remolque más cargado primero, justo detrás del tractor."},
  {"id":2,"q":"El remolque más liviano de un conjunto de dobles o triples debe colocarse:","opts":["Primero, detrás del tractor","Último en la fila","Solo en el medio","Donde quieras"],"re":"El remolque más liviano va al final; nunca pongas uno liviano delante de uno pesado."},
  {"id":3,"q":"Poner un remolque poco cargado delante de uno muy cargado es:","opts":["Recomendado para el equilibrio","Obligatorio por ley","Una mala idea que perjudica el manejo y la estabilidad","Mejor para el ahorro de combustible"],"re":"Un remolque liviano delante de uno pesado empeora el manejo del conjunto y es inseguro."},
  {"id":4,"q":"Una mala distribución del peso entre los remolques afecta principalmente:","opts":["La recepción de la radio","La precisión del medidor de combustible","El color de los remolques","El manejo, el frenado y el riesgo de volcadura"],"re":"Una mala distribución del peso empeora el manejo y el frenado y aumenta el riesgo de volcadura."},
  {"id":5,"q":"En comparación con un solo remolque, un conjunto de dobles o triples necesita:","opts":["Más espacio para maniobrar y detenerse","Menos espacio para maniobrar","Exactamente el mismo espacio","Mucha menos distancia de seguimiento"],"re":"Las combinaciones más largas necesitan más espacio para girar, detenerse y cambiar de carril."},
  {"id":6,"q":"La carga dentro de cada remolque debe estar:","opts":["Cargada solo en la parte trasera","Asegurada y equilibrada para repartir bien el peso","Cargada solo en la parte delantera","Suelta para que se acomode"],"re":"Equilibra y asegura la carga en cada remolque para repartir bien el peso."},
  {"id":7,"q":"Decidir el orden de los remolques por peso es importante porque los remolques traseros:","opts":["No llevan peso","Tienen su propia dirección","Se balancean y amplifican el movimiento más que el delantero","Nunca afectan al tractor"],"re":"Los remolques traseros se balancean más, por eso los más pesados van adelante para dar estabilidad."},
  {"id":8,"q":"Antes de decidir el orden para acoplar los remolques, debes saber:","opts":["Solo los colores de la pintura","La estación de radio","Nada de antemano","El peso relativo de cada remolque cargado"],"re":"Conoce el peso relativo de cada remolque para que el más pesado vaya primero y el más liviano al final."},
  {"id":9,"q":"Un dolly de conversión se describe mejor como:","opts":["Un dispositivo de acople con quinta rueda, una barra de tiro y uno o dos ejes","Un portallantas de repuesto","Un tipo de freno de remolque","Un tanque de combustible con ruedas"],"re":"Un dolly de conversión es una unidad de acople con quinta rueda, barra de tiro y uno o dos ejes."},
  {"id":10,"q":"Un dolly de conversión se conecta al equipo de adelante mediante un:","opts":["Volante","Gancho pintle","Cinturón de seguridad","Pedal de freno"],"re":"La barra de tiro del dolly se acopla al equipo de adelante mediante un gancho pintle."},
  {"id":11,"q":"La parte del dolly donde se traba el perno rey (kingpin) del remolque trasero es:","opts":["El ojo de la barra de tiro","El gancho pintle","La quinta rueda","El guardabarros"],"re":"El perno rey del remolque trasero se traba en la quinta rueda del dolly."},
  {"id":12,"q":"Antes de retroceder bajo un dolly que no está acoplado, debes:","opts":["Dejarlo rodar libremente","Quitarle el eje","Desinflar sus llantas","Asegurarlo con cuñas en las ruedas o aplicando sus frenos"],"re":"Pon cuñas en las ruedas del dolly o aplica sus frenos para que no ruede mientras acoplas."},
  {"id":13,"q":"La barra de tiro (drawbar) de un dolly de conversión:","opts":["Conecta el dolly al gancho pintle del equipo de adelante","Dirige el dolly","Contiene el combustible","Lleva pasajeros"],"re":"La barra de tiro se extiende hacia adelante y se acopla al gancho pintle de la unidad de adelante."},
  {"id":14,"q":"Los dollies y remolques fabricados desde fines de los años noventa tienen:","opts":["Sin frenos","Frenos antibloqueo (ABS)","Ejes direccionales","Transmisiones manuales"],"re":"Los dollies de conversión y los remolques fabricados desde fines de los noventa tienen ABS."},
  {"id":15,"q":"Un dolly de conversión puede tener:","opts":["Solo un volante","Sin ruedas","Uno o dos ejes","Un motor"],"re":"Un dolly de conversión tiene uno o dos ejes debajo de su quinta rueda."},
  {"id":16,"q":"Las cadenas o dispositivos de seguridad en un dolly acoplado sirven para:","opts":["Adornar el equipo","Llevar carga extra","Enfriar los frenos","Asegurar la barra de tiro del dolly al remolque"],"re":"Las cadenas de seguridad aseguran la barra de tiro del dolly al remolque que arrastra."},
  {"id":17,"q":"Tras posicionar el dolly, lo primero en lo que el tractor con el primer remolque debe trabarse es:","opts":["La barra de tiro del dolly con el gancho pintle","El perno rey del remolque trasero","El tren de aterrizaje del remolque","Los guardabarros"],"re":"Retrocede para que el gancho pintle del equipo se trabe en la barra de tiro del dolly."},
  {"id":18,"q":"Una vez trabado el gancho pintle en la barra de tiro, lo siguiente es:","opts":["Arrancar de inmediato","Soltar los frenos del dolly y rodarlo bajo el remolque trasero","Quitar el dolly","Desinflar las llantas"],"re":"Suelta los frenos del dolly y ródalo bajo el remolque trasero para acoplar el perno rey."},
  {"id":19,"q":"Con el dolly bajo el remolque trasero, retrocedes hasta que:","opts":["Las llantas se desinflen","El tractor se apague","El perno rey del remolque trasero se trabe en la quinta rueda del dolly","Se rompa el tren de aterrizaje"],"re":"Retrocede hasta que el perno rey del remolque trasero se trabe firme en la quinta rueda del dolly."},
  {"id":20,"q":"Después de trabar el perno rey, debes conectar:","opts":["Las mangueras de combustible","La articulación de dirección","El tubo de escape","Las líneas de aire y las eléctricas"],"re":"Conecta las líneas de aire y el cable eléctrico (de luces) después de hacer el acople."},
  {"id":21,"q":"Para confirmar que un acople está seguro, debes hacer una:","opts":["Prueba de tirón jalando suavemente contra el acople","Prueba de claxon","Prueba de pintura","Prueba de combustible"],"re":"Haz una prueba de tirón suave para asegurarte de que el acople está trabado antes de conducir."},
  {"id":22,"q":"Al acoplar, las conexiones de aire (glad hands) deben estar:","opts":["Cruzadas a propósito","Conectadas a los acopladores correctos, sin cruzarse","Desconectadas","Llenas de aceite"],"re":"Conecta las glad hands a los acopladores correctos; cruzarlas manda aire a los frenos equivocados."},
  {"id":23,"q":"Antes de rodar el dolly bajo el remolque trasero, ese remolque debe estar:","opts":["Avanzando hacia adelante","Inclinado de lado","Sostenido a la altura correcta con frenos puestos o ruedas con cuñas","Totalmente descargado"],"re":"El remolque trasero debe estar a la altura correcta con frenos puestos o ruedas con cuñas."},
  {"id":24,"q":"Verificar visualmente que no hay espacio entre la quinta rueda y la base del remolque indica que:","opts":["Las llantas están infladas","El combustible está lleno","Las luces funcionan","El acople está completamente asentado y trabado"],"re":"Sin espacio en la quinta rueda significa que el acople está completamente asentado y trabado."},
  {"id":25,"q":"La secuencia correcta para acoplar un segundo remolque es:","opts":["Acoplar pintle a barra de tiro, rodar el dolly debajo, trabar el perno rey, conectar líneas, prueba de tirón","Conectar el aire primero y luego buscar el dolly","Prueba de tirón primero y luego retroceder","Avanzar hacia adelante para acoplar"],"re":"Pintle a barra de tiro, rodar el dolly debajo, trabar el perno rey, conectar líneas y luego prueba de tirón."},
  {"id":26,"q":"Antes de desenganchar un dolly de conversión, primero debes:","opts":["Avanzar rápido hacia adelante","Bajar su tren de aterrizaje o soportes y poner los frenos del remolque","Desconectar la dirección","Vaciar el tanque de combustible"],"re":"Pon los frenos del remolque y baja los soportes para que nada ruede ni caiga al desacoplar."},
  {"id":27,"q":"Al separar dobles o triples, debes desacoplar:","opts":["El remolque delantero primero","Cualquier remolque en cualquier orden","El remolque trasero y el dolly primero","Solo el tractor al final"],"re":"Desacopla el remolque trasero y el dolly primero, luego avanza hacia adelante."},
  {"id":28,"q":"Antes de desconectar el dolly del remolque, debes:","opts":["Alejarte con las líneas todavía conectadas","Dejar el perno rey trabado","Inflar las llantas del dolly","Bajar el soporte del dolly, desconectar las líneas y luego destrabar la quinta rueda"],"re":"Baja el soporte, desconecta las líneas y luego libera la quinta rueda antes de alejarte."},
  {"id":29,"q":"Al desenganchar el gancho pintle, la barra de tiro del dolly puede ser pesada, por eso debes:","opts":["Estar listo para sostenerla cuando se libere","Dejarla caer sin cuidado","Pararte justo debajo de ella","No tocarla nunca"],"re":"Sostén la barra de tiro al liberar el gancho pintle para que no te caiga encima."},
  {"id":30,"q":"Las líneas de aire y eléctricas deben desconectarse y:","opts":["Dejarse arrastrando por el suelo","Asegurarse para que no se arrastren ni se dañen","Cortarse","Llenarse de agua"],"re":"Asegura las líneas tras desconectarlas para que no se arrastren ni se dañen."},
  {"id":31,"q":"Antes de retirar el tractor y el remolque delantero del dolly, asegúrate de que:","opts":["La radio esté apagada","La tapa de combustible esté puesta","El dolly esté sostenido y su perno rey destrabado","Los espejos estén plegados"],"re":"Confirma que el dolly esté sostenido y destrabado antes de retirar el equipo."},
  {"id":32,"q":"Poner los frenos del remolque trasero antes de desacoplar ayuda a evitar que el remolque:","opts":["Cambie de color","Use combustible","Toque el claxon","Se ruede"],"re":"Pon los frenos del remolque para que no pueda rodarse mientras desacoplas."},
  {"id":33,"q":"Bajar el tren de aterrizaje del remolque antes de desacoplar evita que el remolque:","opts":["Caiga de golpe al quitar el dolly","Se pinche una llanta","Pierda sus luces","Se sobrecaliente"],"re":"Baja el tren de aterrizaje para que el remolque quede sostenido y no caiga al desacoplar."},
  {"id":34,"q":"La amplificación trasera, o efecto látigo (crack-the-whip), significa que un giro brusco del volante:","opts":["No afecta a los remolques","Se amplifica hacia el remolque trasero, que puede salirse mucho","Se reduce hacia atrás","Solo afecta al tractor"],"re":"Un pequeño giro en el tractor se amplifica atrás, lanzando al último remolque muy lejos."},
  {"id":35,"q":"En un conjunto de dobles o triples, el remolque con más probabilidad de volcar es:","opts":["El primer remolque","El tractor","El último remolque","Ninguno"],"re":"El efecto látigo hace que el último remolque sea el más propenso a inclinarse o volcar."},
  {"id":36,"q":"Para reducir el efecto látigo, debes girar el volante:","opts":["Rápido y brusco","Solo con una mano","Lo más rápido posible","Suave y gradualmente"],"re":"Gira suave y gradualmente para que el remolque trasero no se salga."},
  {"id":37,"q":"Para bajar el riesgo de volcadura con dobles y triples, debes:","opts":["Bajar la velocidad antes de las curvas y evitar cambios de carril bruscos","Acelerar en las curvas","Frenar fuerte en la curva","Hacer movimientos repentinos"],"re":"Baja la velocidad antes de las curvas y evita giros o cambios de carril bruscos."},
  {"id":38,"q":"Como los dobles y triples se desvían más (off-track), en las curvas debes:","opts":["Cortar la esquina","Abrirte lo suficiente para que los remolques sigan bien la trayectoria","Ignorar los remolques","Pasar la curva rápido"],"re":"Los equipos largos se desvían, así que ábrete lo suficiente para que los remolques traseros sigan."},
  {"id":39,"q":"Los cambios de carril repentinos con dobles o triples son peligrosos porque pueden:","opts":["Ahorrar tiempo con seguridad","Mejorar el frenado","Provocar el efecto látigo y una volcadura","Ayudar a los remolques a seguir la trayectoria"],"re":"Un cambio de carril repentino puede provocar el efecto látigo y volcar el remolque trasero."},
  {"id":40,"q":"En caminos resbalosos, los dobles y triples requieren:","opts":["Mayor velocidad","Frenado fuerte","Dirección brusca","Mucha precaución y un manejo suave y lento"],"re":"Reduce la velocidad y maneja con suavidad; las combinaciones largas patinan y se cierran en tijera más fácil."},
  {"id":41,"q":"Retroceder un conjunto de dobles o triples es:","opts":["Mucho más difícil y normalmente debe evitarse","Más fácil que un solo remolque","Exactamente igual","Imposible de aprender"],"re":"Los dobles y triples son muy difíciles de retroceder; evítalo cuando puedas."},
  {"id":42,"q":"Para evitar que el remolque trasero se salga, tu mejor estrategia es:","opts":["Manejar más rápido","Anticiparte y hacer movimientos suaves y graduales","Girar el volante de golpe","Pegarte al de adelante para ahorrar espacio"],"re":"Anticípate y dirige con suavidad para que el remolque trasero nunca tenga ocasión de salirse."},
  {"id":43,"q":"Para suministrar aire a todos los remolques, las válvulas de cierre (cut-out) traseras de cada remolque deben estar abiertas EXCEPTO en:","opts":["El primer remolque","Solo el dolly","El último remolque, donde deben estar cerradas","El tractor"],"re":"Abre las válvulas de cierre de cada remolque excepto en el último, cuyas válvulas traseras quedan cerradas."},
  {"id":44,"q":"Si una válvula de cierre en medio del equipo queda cerrada, los remolques detrás de ella:","opts":["Frenan mejor","Aceleran","Cargan más rápido","No reciben aire en sus frenos"],"re":"Una válvula de cierre intermedia cerrada corta el aire a todos los remolques detrás de ella."},
  {"id":45,"q":"Durante la inspección previa, el gancho pintle debe revisarse para asegurar que esté:","opts":["Pintado de un color llamativo","Enganchado, trabado y sin desgaste ni daño","Lleno solo de grasa","Flojo para dar flexibilidad"],"re":"El gancho pintle debe estar enganchado, trabado y sin desgaste ni daño excesivo."},
  {"id":46,"q":"Antes de conducir, debes cargar el sistema de aire y luego:","opts":["Abrir las válvulas traseras del último remolque","Comprobar que el aire llega a todos los remolques y que los frenos funcionan","Drenar todos los tanques","Desconectar las glad hands"],"re":"Carga el sistema y confirma que el aire llega a todos los remolques y que los frenos aplican."},
  {"id":47,"q":"Al inspeccionar las glad hands en dobles y triples, debes verificar que estén:","opts":["Cruzadas para equilibrar","Quitadas por completo","Conectadas correctamente y sin cruzarse","Envueltas en cinta"],"re":"Las glad hands deben estar conectadas a los acopladores correctos y sin cruzarse."},
  {"id":48,"q":"Parte de inspeccionar un dolly de conversión es revisar su:","opts":["Radio y asientos","Inyectores de combustible","Volante","Quinta rueda, traba del perno rey, llantas y luces"],"re":"Inspecciona la quinta rueda del dolly, la traba del perno rey, las llantas, las luces y las conexiones de aire."},
  {"id":49,"q":"Para probar que los frenos de servicio del remolque funcionan tras acoplar, puedes:","opts":["Tocar el claxon","Cargar el aire, aplicar los frenos y comprobar que los frenos traseros se aplican","Drenar los tanques","Cruzar las glad hands"],"re":"Carga el aire, aplica los frenos y confirma que los frenos del remolque se aplican y sueltan."},
  {"id":50,"q":"La posición correcta de la válvula de cierre trasera en el último remolque es:","opts":["Abierta","Medio abierta","Quitada","Cerrada"],"re":"Las válvulas de cierre traseras del último remolque deben estar cerradas para retener el aire en el sistema."}
];
